SELECT COUNT(event_reservation_users.id) AS count FROM event_reservations LEFT JOIN event_reservation_users ON event_reservations.id = event_reservation_users.reservation_id WHERE event_reservations.id = UUID_TO_BIN(/*reservationId*/'aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee') AND event_reservations.event_id = UUID_TO_BIN(/*eventId*/'aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee') GROUP BY event_reservations.id HAVING COUNT(event_reservations.id) > 0